		rows: ReadonlyArray<
			PlotSummary & {
				reasons: ReadonlyArray<"paused_run" | "merged_pr_unreviewed" | "stale_draft">;
			}
		>,
	): PlotAggregator {
		return {
			async listSummaries() {
				return rows;
			},
			async listNeedsAttention() {
				return rows;
			},
			async countNeedsAttention() {
				return rows.length;
			},
			invalidate() {},
		};
	}

	test("returns aggregator listNeedsAttention rows under the `plots` key", async () => {
		const rows = [
